import{_ as i,o as t,c as a,ae as o}from"./chunks/framework.CB71nIlf.js";const g=JSON.parse('{"title":"技术问题","description":"","frontmatter":{},"headers":[],"relativePath":"1-FAQ/3-technical.md","filePath":"1-FAQ/3-technical.md"}'),r={name:"1-FAQ/3-technical.md"};function n(e,l,s,d,u,h){return t(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="技术问题" tabindex="-1">技术问题 <a class="header-anchor" href="#技术问题" aria-label="Permalink to &quot;技术问题&quot;">​</a></h1><h2 id="浏览器兼容性" tabindex="-1">浏览器兼容性 <a class="header-anchor" href="#浏览器兼容性" aria-label="Permalink to &quot;浏览器兼容性&quot;">​</a></h2><h3 id="q15-支持哪些浏览器" tabindex="-1">Q15: 支持哪些浏览器？ <a class="header-anchor" href="#q15-支持哪些浏览器" aria-label="Permalink to &quot;Q15: 支持哪些浏览器？&quot;">​</a></h3><p><strong>A</strong>: 推荐使用以下浏览器的最新版本：</p><table tabindex="0"><thead><tr><th>浏览器</th><th>最低版本</th><th>推荐版本</th><th>状态</th></tr></thead><tbody><tr><td>Chrome</td><td>90+</td><td>最新版</td><td>✅ 完全支持</td></tr><tr><td>Firefox</td><td>88+</td><td>最新版</td><td>✅ 完全支持</td></tr><tr><td>Safari</td><td>14+</td><td>最新版</td><td>✅ 完全支持</td></tr><tr><td>Edge</td><td>90+</td><td>最新版</td><td>✅ 完全支持</td></tr><tr><td>IE</td><td>-</td><td>-</td><td>❌ 不支持</td></tr></tbody></table><p><strong>注意事项</strong>：</p><ul><li>不支持IE浏览器</li><li>建议启用JavaScript</li><li>建议启用Cookie</li><li>部分实验可能需要特定浏览器功能</li></ul><h2 id="文件上传" tabindex="-1">文件上传 <a class="header-anchor" href="#文件上传" aria-label="Permalink to &quot;文件上传&quot;">​</a></h2><h3 id="q17-文件上传失败怎么办" tabindex="-1">Q17: 文件上传失败怎么办？ <a class="header-anchor" href="#q17-文件上传失败怎么办" aria-label="Permalink to &quot;Q17: 文件上传失败怎么办？&quot;">​</a></h3><p><strong>A</strong>: 请检查以下几点：</p><ol><li><p><strong>文件大小</strong></p><ul><li>检查文件大小是否超过限制</li><li>压缩文件或分批上传</li></ul></li><li><p><strong>文件格式</strong></p><ul><li>检查文件格式是否正确</li><li>转换为支持的格式（CSV、JSON等）</li></ul></li><li><p><strong>网络连接</strong></p><ul><li>检查网络连接是否稳定</li><li>重新上传</li></ul></li><li><p><strong>存储空间</strong></p><ul><li>联系管理员检查服务器存储空间</li></ul></li></ol><p><strong>支持的文件格式</strong>：</p><ul><li>CSV（逗号分隔值）</li><li>JSON（JavaScript对象表示法）</li><li>TXT（纯文本）</li><li>ZIP（压缩文件）</li></ul><p>详细排查：<a href="/cogniand-manual.github.io/6-troubleshooting/3-upload-issues.html">故障排除 - 数据上传问题</a></p><h3 id="q18-页面显示异常怎么办" tabindex="-1">Q18: 页面显示异常怎么办？ <a class="header-anchor" href="#q18-页面显示异常怎么办" aria-label="Permalink to &quot;Q18: 页面显示异常怎么办？&quot;">​</a></h3><p><strong>A</strong>: 请尝试以下方法：</p><ol><li><p><strong>刷新页面</strong></p><ul><li>Windows: <code>Ctrl + F5</code></li><li>Mac: <code>Cmd + Shift + R</code></li></ul></li><li><p><strong>清除缓存</strong></p><ul><li>清除浏览器缓存和Cookie</li><li>重新访问平台</li></ul></li><li><p><strong>无痕模式</strong></p><ul><li>使用浏览器的无痕/隐私模式访问</li><li>排除缓存和扩展影响</li></ul></li><li><p><strong>更新浏览器</strong></p><ul><li>更新浏览器到最新版本</li><li>重启浏览器</li></ul></li></ol><p><strong>清除缓存步骤</strong>：</p><ul><li>Chrome: 设置 → 隐私和安全 → 清除浏览数据</li><li>Firefox: 选项 → 隐私与安全 → Cookie和网站数据 → 清除数据</li><li>Safari: 偏好设置 → 隐私 → 管理网站数据 → 移除全部</li></ul><h2 id="性能问题" tabindex="-1">性能问题 <a class="header-anchor" href="#性能问题" aria-label="Permalink to &quot;性能问题&quot;">​</a></h2><h3 id="q19-页面加载缓慢怎么办" tabindex="-1">Q19: 页面加载缓慢怎么办？ <a class="header-anchor" href="#q19-页面加载缓慢怎么办" aria-label="Permalink to &quot;Q19: 页面加载缓慢怎么办？&quot;">​</a></h3><p><strong>A</strong>: 可能的原因和解决方案：</p><ol><li><p><strong>网络速度慢</strong></p><ul><li>检查网络连接速度</li><li>尝试使用更快的网络</li><li>避开网络高峰时段</li></ul></li><li><p><strong>服务器负载高</strong></p><ul><li>避开高峰时段访问</li><li>联系管理员检查服务器状态</li></ul></li><li><p><strong>浏览器缓存过多</strong></p><ul><li>清除浏览器缓存</li><li>使用无痕模式访问</li></ul></li><li><p><strong>数据量过大</strong></p><ul><li>使用分页功能</li><li>使用筛选功能减少数据量</li><li>减少一次性加载的数据</li></ul></li></ol><p><strong>优化建议</strong>：</p><ul><li>关闭不必要的浏览器标签页</li><li>关闭不必要的浏览器扩展</li><li>定期清理浏览器缓存</li><li>使用有线网络代替WiFi</li></ul><h2 id="邮件接收" tabindex="-1">邮件接收 <a class="header-anchor" href="#邮件接收" aria-label="Permalink to &quot;邮件接收&quot;">​</a></h2><h3 id="q20-未收到验证邮件或重置邮件怎么办" tabindex="-1">Q20: 未收到验证邮件或重置邮件怎么办？ <a class="header-anchor" href="#q20-未收到验证邮件或重置邮件怎么办" aria-label="Permalink to &quot;Q20: 未收到验证邮件或重置邮件怎么办？&quot;">​</a></h3><p><strong>A</strong>: 请检查以下几点：</p><ol><li><p><strong>垃圾邮件文件夹</strong></p><ul><li>检查垃圾邮件/垃圾箱</li><li>将平台邮箱加入白名单</li></ul></li><li><p><strong>邮箱地址</strong></p><ul><li>检查注册时填写的邮箱是否正确</li><li>重新注册或联系管理员修改</li></ul></li><li><p><strong>邮件延迟</strong></p><ul><li>等待几分钟后再检查</li><li>点击&quot;重新发送&quot;按钮</li></ul></li><li><p><strong>邮件服务器</strong></p><ul><li>联系管理员检查邮件服务器配置</li><li>确认SMTP服务正常</li></ul></li></ol><p><strong>平台邮箱地址</strong>：</p><ul><li>支持邮箱：um.andlab@gmail.com</li></ul><p>详细排查：<a href="/cogniand-manual.github.io/6-troubleshooting/4-email-issues.html">故障排除 - 邮件接收问题</a></p><p>联系方式：<a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a></p><hr><p><strong>还有其他技术问题？</strong> 请查看：</p><ul><li><a href="/cogniand-manual.github.io/6-troubleshooting/">故障排除</a></li><li><a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a></li></ul>',36)])])}const c=i(r,[["render",n]]);export{g as __pageData,c as default};
